-- ---------------------------------------------------------------------
-- FILE: db/schema/migrations/create_device_assignment_table.sql
-- ---------------------------------------------------------------------
SET QUOTED_IDENTIFIER ON; SET ANSI_NULLS ON;
GO
-- =============================================================================
-- Migration: Create DeviceAssignment Table
-- Description: Tracks invasive devices (central line, urinary catheter, ETT) that
--              drive CLABSI/CAUTI/VAP risk. Unlike RestraintOrder (one ACTIVE row
--              per admission), a patient can have multiple concurrent device types
--              at once, so the "one active" rule is scoped per (admission, device
--              type) via UX_DA_AdmissionDeviceTypeActive. InsertedAt/RemovedAt span
--              feeds device-days for the hospital-level infection-rate view.
-- =============================================================================

IF OBJECT_ID('dbo.DeviceAssignment', 'U') IS NULL
BEGIN
    CREATE TABLE dbo.DeviceAssignment
    (
        DeviceAssignmentId  UNIQUEIDENTIFIER NOT NULL
            CONSTRAINT DF_DEVA_Id DEFAULT NEWSEQUENTIALID(),

        HospitalId          UNIQUEIDENTIFIER NOT NULL,
        AdmissionId         UNIQUEIDENTIFIER NOT NULL,
        EncounterId         UNIQUEIDENTIFIER NULL,
        PatientId           NVARCHAR(50)     NULL,

        DeviceType          NVARCHAR(30)     NOT NULL,   -- CENTRAL_LINE / URINARY_CATHETER / ETT

        InsertionSite       NVARCHAR(100)    NULL,
        Indication          NVARCHAR(300)    NULL,

        InsertedByDoctorName NVARCHAR(200)   NOT NULL,
        InsertedAt          DATETIME2(3)     NOT NULL CONSTRAINT DF_DEVA_InsertedAt DEFAULT (SYSUTCDATETIME()),

        RemovedAt           DATETIME2(3)     NULL,
        RemovedBy           NVARCHAR(150)    NULL,
        RemovedByUserId     UNIQUEIDENTIFIER NULL,
        RemovalReason       NVARCHAR(300)    NULL,

        StatusCode          NVARCHAR(20)     NOT NULL
            CONSTRAINT DF_DEVA_Status DEFAULT ('ACTIVE'),   -- ACTIVE / REMOVED

        Notes               NVARCHAR(500)    NULL,

        CreatedAt           DATETIME2(3)     NOT NULL CONSTRAINT DF_DEVA_CreatedAt DEFAULT (SYSUTCDATETIME()),
        CreatedBy           NVARCHAR(100)    NULL,
        UpdatedAt           DATETIME2(3)     NOT NULL CONSTRAINT DF_DEVA_UpdatedAt DEFAULT (SYSUTCDATETIME()),
        UpdatedBy           NVARCHAR(100)    NULL,

        RowVersion          ROWVERSION       NOT NULL,

        CONSTRAINT PK_DeviceAssignment PRIMARY KEY CLUSTERED (DeviceAssignmentId),
        CONSTRAINT FK_DEVA_Admission FOREIGN KEY (AdmissionId) REFERENCES dbo.Admission(AdmissionId),
        CONSTRAINT CK_DEVA_DeviceType CHECK (DeviceType IN ('CENTRAL_LINE','URINARY_CATHETER','ETT')),
        CONSTRAINT CK_DEVA_Status CHECK (StatusCode IN ('ACTIVE','REMOVED')),
        CONSTRAINT CK_DEVA_RemovalConsistency CHECK (
            (StatusCode = 'ACTIVE' AND RemovedAt IS NULL)
            OR
            (StatusCode = 'REMOVED' AND RemovedAt IS NOT NULL)
        )
    );

    PRINT 'Created table DeviceAssignment';
END
GO

-- Only one ACTIVE device per (admission, device type) at a time -- a patient can have
-- an active central line AND catheter AND ETT concurrently, just not two active central
-- lines simultaneously.
IF NOT EXISTS (SELECT 1 FROM sys.indexes WHERE name = 'UX_DEVA_AdmissionDeviceTypeActive' AND object_id = OBJECT_ID('dbo.DeviceAssignment'))
BEGIN
    CREATE UNIQUE INDEX UX_DEVA_AdmissionDeviceTypeActive
    ON dbo.DeviceAssignment(HospitalId, AdmissionId, DeviceType)
    WHERE StatusCode = 'ACTIVE';
END
GO

IF NOT EXISTS (SELECT 1 FROM sys.indexes WHERE name = 'IX_DEVA_AdmissionHistory' AND object_id = OBJECT_ID('dbo.DeviceAssignment'))
    CREATE INDEX IX_DEVA_AdmissionHistory ON dbo.DeviceAssignment (HospitalId, AdmissionId, InsertedAt DESC);
GO

GO

-- ---------------------------------------------------------------------
-- FILE: db/schema/migrations/create_device_care_bundle_check_table.sql
-- ---------------------------------------------------------------------
SET QUOTED_IDENTIFIER ON; SET ANSI_NULLS ON;
GO
-- =============================================================================
-- Migration: Create DeviceCareBundleCheck Table
-- Description: Logs a CLABSI/CAUTI/VAP care-bundle compliance check against an
--              active device. Insert-only (real bundles are checked every shift,
--              not once a day, so this is a timestamped log rather than a
--              one-row-per-calendar-day upsert). Item-level compliance is stored
--              as a compact ItemsJson blob rather than a child table -- the item
--              set per device type is a short, fixed, backend-constant list
--              (IpdConstants.CareBundleItems) that nothing queries at the item
--              level; CompliantCount/TotalItems/AllCompliant are computed and
--              trusted only from the server, never the client.
-- =============================================================================

IF OBJECT_ID('dbo.DeviceCareBundleCheck', 'U') IS NULL
BEGIN
    CREATE TABLE dbo.DeviceCareBundleCheck
    (
        CheckId             UNIQUEIDENTIFIER NOT NULL
            CONSTRAINT DF_DCBC_Id DEFAULT NEWSEQUENTIALID(),

        HospitalId          UNIQUEIDENTIFIER NOT NULL,
        AdmissionId         UNIQUEIDENTIFIER NOT NULL,
        DeviceAssignmentId  UNIQUEIDENTIFIER NOT NULL,
        DeviceType          NVARCHAR(30)     NOT NULL,   -- denormalized from DeviceAssignment for board batching

        ItemsJson           NVARCHAR(MAX)    NOT NULL,
        CompliantCount      INT              NOT NULL,
        TotalItems          INT              NOT NULL,
        AllCompliant        BIT              NOT NULL,

        Notes               NVARCHAR(500)    NULL,

        CheckedBy           NVARCHAR(200)    NOT NULL,
        CheckedByUserId     UNIQUEIDENTIFIER NULL,
        CheckedAt           DATETIME2(3)     NOT NULL CONSTRAINT DF_DCBC_CheckedAt DEFAULT (SYSUTCDATETIME()),

        CreatedAt           DATETIME2(3)     NOT NULL CONSTRAINT DF_DCBC_CreatedAt DEFAULT (SYSUTCDATETIME()),
        CreatedBy           NVARCHAR(100)    NULL,

        RowVersion          ROWVERSION       NOT NULL,

        CONSTRAINT PK_DeviceCareBundleCheck PRIMARY KEY CLUSTERED (CheckId),
        CONSTRAINT FK_DCBC_Admission FOREIGN KEY (AdmissionId) REFERENCES dbo.Admission(AdmissionId),
        CONSTRAINT FK_DCBC_DeviceAssignment FOREIGN KEY (DeviceAssignmentId) REFERENCES dbo.DeviceAssignment(DeviceAssignmentId),
        CONSTRAINT CK_DCBC_DeviceType CHECK (DeviceType IN ('CENTRAL_LINE','URINARY_CATHETER','ETT'))
    );

    PRINT 'Created table DeviceCareBundleCheck';
END
GO

IF NOT EXISTS (SELECT 1 FROM sys.indexes WHERE name = 'IX_DCBC_DeviceTimeline' AND object_id = OBJECT_ID('dbo.DeviceCareBundleCheck'))
    CREATE INDEX IX_DCBC_DeviceTimeline ON dbo.DeviceCareBundleCheck (DeviceAssignmentId, CheckedAt DESC);
GO

GO

-- ---------------------------------------------------------------------
-- FILE: db/schema/migrations/create_discharge_config_tables.sql
-- ---------------------------------------------------------------------
SET QUOTED_IDENTIFIER ON; SET ANSI_NULLS ON;
GO
-- Discharge Summary personalization + letterhead (Phase 2 of the Discharge/Prescription-parity
-- build). Mirrors DoctorPrescriptionFieldConfigs / PrescriptionSettings one-for-one, adapted to
-- Discharge; no cross-table FK between the two, so no create_tables_zz_foreign_keys.sql ordering
-- concern here.

-- Per-doctor (global) discharge-summary field layout: rename / reorder / show-hide built-in fields
-- and add custom fields. One row per doctor; ConfigJson holds the ordered field list as JSON.
IF OBJECT_ID('dbo.DoctorDischargeFieldConfigs', 'U') IS NULL
BEGIN
    CREATE TABLE dbo.DoctorDischargeFieldConfigs (
        ConfigId      UNIQUEIDENTIFIER NOT NULL
            CONSTRAINT PK_DoctorDischargeFieldConfigs PRIMARY KEY
            CONSTRAINT DF_DoctorDischargeFieldConfigs_ConfigId DEFAULT NEWID(),
        DoctorId      UNIQUEIDENTIFIER NOT NULL,
        ConfigJson    NVARCHAR(MAX) NULL,
        CreatedAtUtc  DATETIME2(3) NOT NULL CONSTRAINT DF_DoctorDischargeFieldConfigs_CreatedAt DEFAULT SYSUTCDATETIME(),
        UpdatedAtUtc  DATETIME2(3) NOT NULL CONSTRAINT DF_DoctorDischargeFieldConfigs_UpdatedAt DEFAULT SYSUTCDATETIME()
    );
END
GO

IF NOT EXISTS (SELECT 1 FROM sys.indexes WHERE name = 'UX_DoctorDischargeFieldConfigs_DoctorId' AND object_id = OBJECT_ID('dbo.DoctorDischargeFieldConfigs'))
    CREATE UNIQUE INDEX UX_DoctorDischargeFieldConfigs_DoctorId ON dbo.DoctorDischargeFieldConfigs(DoctorId);
GO

-- Per-doctor+hospital discharge-summary letterhead: an uploaded PDF background template plus
-- margins/typography/overflow behavior. Mirrors PrescriptionSettings minus ValidDuration (a
-- discharge certificate has no "valid for N days" concept).
IF OBJECT_ID('dbo.DischargeSettings', 'U') IS NULL
BEGIN
    CREATE TABLE dbo.DischargeSettings (
        DischargeSettingId UNIQUEIDENTIFIER NOT NULL
            CONSTRAINT PK_DischargeSettings PRIMARY KEY
            CONSTRAINT DF_DischargeSettings_Id DEFAULT NEWID(),

        HospitalId UNIQUEIDENTIFIER NOT NULL,
        DoctorId   UNIQUEIDENTIFIER NOT NULL,

        HeaderHeight       INT     NULL CONSTRAINT DF_DischargeSettings_HeaderHeight DEFAULT (20),
        FooterHeight       INT     NULL CONSTRAINT DF_DischargeSettings_FooterHeight DEFAULT (20),
        ContentLeftMargin  INT     NULL CONSTRAINT DF_DischargeSettings_LeftMargin   DEFAULT (20),
        ContentRightMargin INT     NULL CONSTRAINT DF_DischargeSettings_RightMargin  DEFAULT (20),
        OverFlowPage       BIT     NULL CONSTRAINT DF_DischargeSettings_Overflow     DEFAULT (1),

        FontFamily NVARCHAR(100)  NULL,
        FontSize   INT            NULL CONSTRAINT DF_DischargeSettings_FontSize DEFAULT (11),
        FontWeight NVARCHAR(50)   NULL,
        TextColour NVARCHAR(50)   NULL,
        URI        NVARCHAR(2048) NULL,

        CreatedByUserId UNIQUEIDENTIFIER NULL,
        CreatedAt DATETIME2(3) NOT NULL
            CONSTRAINT DF_DischargeSettings_Created DEFAULT SYSUTCDATETIME(),
        UpdatedAt DATETIME2(3) NOT NULL
            CONSTRAINT DF_DischargeSettings_Updated DEFAULT SYSUTCDATETIME(),

        RowVersion ROWVERSION NOT NULL,

        CONSTRAINT UQ_DischargeSettings_H_D UNIQUE (HospitalId, DoctorId),

        CONSTRAINT CK_DischargeSettings_HeaderHeight_Pos  CHECK (HeaderHeight       IS NULL OR HeaderHeight       >= 0),
        CONSTRAINT CK_DischargeSettings_FooterHeight_Pos  CHECK (FooterHeight       IS NULL OR FooterHeight       >= 0),
        CONSTRAINT CK_DischargeSettings_LeftMargin_Pos    CHECK (ContentLeftMargin  IS NULL OR ContentLeftMargin  >= 0),
        CONSTRAINT CK_DischargeSettings_RightMargin_Pos   CHECK (ContentRightMargin IS NULL OR ContentRightMargin >= 0),
        CONSTRAINT CK_DischargeSettings_FontSize_Range    CHECK (FontSize           IS NULL OR (FontSize BETWEEN 5 AND 72)),
        CONSTRAINT CK_DischargeSettings_TextColour_Hex CHECK (
            TextColour IS NULL OR
            TextColour LIKE N'#________' OR
            TextColour LIKE N'#______'
        )
    );
END
GO

GO

-- ---------------------------------------------------------------------
-- FILE: db/schema/migrations/create_discharge_config_tables__add_hospital.sql
