MERGE dbo.LookupMaster AS t
USING src AS s
  ON t.LookupTypeId = (SELECT LookupTypeId FROM dbo.LookupTypes WHERE LookupTypeCode = N'ICD10')
  AND t.Code = s.Code
WHEN NOT MATCHED THEN
  INSERT (LookupTypeId, Code, [Name], IsActive, CreatedAt, ModifiedAt)
  VALUES ((SELECT LookupTypeId FROM dbo.LookupTypes WHERE LookupTypeCode = N'ICD10'), s.Code, s.Name, 1, SYSUTCDATETIME(), SYSUTCDATETIME());


COMMIT TRAN;
END TRY
